class Solution {
public:
    std::vector<std::vector<long long>> processPackets(int n, int k, const std::vector<std::vector<long long>>& packets) {
        int m = std::min<int>(n, packets.size());
        std::vector<std::vector<long long>> ans;
        if (k <= 0 || k > m) return ans;

        std::vector<long long> ids(m), priorities(m);
        for (int i = 0; i < m; ++i) {
            ids[i] = packets[i][0];
            priorities[i] = packets[i][1];
        }

        std::vector<int> nextGreater(m, -1);
        std::vector<int> stack;

        for (int i = 0; i < m; ++i) {
            while (!stack.empty() && priorities[stack.back()] < priorities[i]) {
                nextGreater[stack.back()] = i;
                stack.pop_back();
            }
            stack.push_back(i);
        }

        for (int start = 0; start + k <= m; ++start) {
            int end = start + k - 1;
            std::vector<long long> window;
            for (int i = start; i <= end; ++i) {
                int j = nextGreater[i];
                if (j != -1 && j <= end) window.push_back(ids[j]);
            }
            if (!window.empty()) ans.push_back(window);
        }
        return ans;
    }
};
